+/**
+ * Email notification adapter — delivers notifications via email.
+ *
+ * This is a stub implementation that logs emails in-memory rather than
+ * sending them through an actual SMTP server. The interface is real and
+ * production-ready; swap the send() internals for real delivery.
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type { NotificationPayload, NotificationResult } from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+export interface EmailMessage {
+  to: string;
+  subject: string;
+  body: string;
+  sentAt: Date;
+}
+
+export class EmailAdapter implements NotificationAdapter {
+  readonly channel = 'email' as const;
+  private logger = new Logger('EmailAdapter');
+  private sentEmails: EmailMessage[] = [];
+
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    try {
+      this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);
+
+      const email: EmailMessage = {
+        to: payload.recipient,
+        subject: payload.subject,
+        body: payload.body,
+        sentAt: new Date(),
+      };
+
+      // In production, this would call an SMTP service or email API.
+      // For now, store in memory.
+      this.sentEmails.push(email);
+
+      return {
+        notificationId: payload.id,
+        channel: 'email',
+        success: true,
+        deliveredAt: email.sentAt,
+      };
+    } catch (err) {
+      const errorMessage = err instanceof Error ? err.message : String(err);
+      this.logger.error(`Failed to send email to ${payload.recipient}: ${errorMessage}`);
+
+      return {
+        notificationId: payload.id,
+        channel: 'email',
+        success: false,
+        error: errorMessage,
+        deliveredAt: new Date(),
+      };
+    }
+  }
+
+  /** Get all sent emails (for testing). */
+  getSentEmails(): EmailMessage[] {
+    return [...this.sentEmails];
+  }
+
+  /** Clear sent emails (for testing). */
+  clearSentEmails(): void {
+    this.sentEmails = [];
+  }
+}

