/**
 * Notification model — core types for the notification system.
 *
 * Architecture: All notifications flow through EventBus. Services emit
 * domain events (e.g., order:created), the NotificationService listens
 * and dispatches to registered NotificationAdapters (email, webhook, etc.).
 *
 * Constraints:
 * - All adapters must implement the NotificationAdapter interface
 * - All notifications must go through EventBus.emit()
 * - No direct service-to-service calls for notification delivery
 */

/**
 * Supported notification channels. Each channel has a corresponding
 * adapter that implements NotificationAdapter.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app' | 'sms';

/**
 * Notification types correspond to the domain events that trigger them.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'welcome'
  | 'user-updated';

/**
 * Priority levels for notification delivery ordering.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'critical';

/**
 * The payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  /** Unique notification ID */
  id: string;
  /** The type of notification being sent */
  type: NotificationType;
  /** The channel this notification should be delivered through */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Notification subject/title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Delivery priority */
  priority: NotificationPriority;
  /** When the notification was created */
  createdAt: Date;
  /** Optional key-value metadata for adapter-specific data */
  metadata?: Record<string, unknown>;
}

/**
 * Result of a notification delivery attempt.
 */
export interface NotificationResult {
  /** The notification that was sent */
  notificationId: string;
  /** The channel used for delivery */
  channel: NotificationChannel;
  /** Whether delivery succeeded */
  success: boolean;
  /** Error message if delivery failed */
  error?: string;
  /** When delivery was attempted */
  deliveredAt: Date;
}

/**
 * A persisted notification record combining payload and delivery results.
 */
export interface Notification {
  /** The full notification payload */
  payload: NotificationPayload;
  /** Results from each delivery attempt */
  results: NotificationResult[];
  /** Current delivery status */
  status: 'pending' | 'sent' | 'failed' | 'partial';
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs emails in-memory rather than
 * sending them through an actual SMTP server. The interface is real and
 * production-ready; swap the send() internals for real delivery.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: EmailMessage[] = [];

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

      const email: EmailMessage = {
        to: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        sentAt: new Date(),
      };

      // In production, this would call an SMTP service or email API.
      // For now, store in memory.
      this.sentEmails.push(email);

      return {
        notificationId: payload.id,
        channel: 'email',
        success: true,
        deliveredAt: email.sentAt,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to send email to ${payload.recipient}: ${errorMessage}`);

      return {
        notificationId: payload.id,
        channel: 'email',
        success: false,
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /** Get all sent emails (for testing). */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /** Clear sent emails (for testing). */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — dispatches notifications through registered adapters
 * in response to EventBus events.
 *
 * Architecture: Event-driven, exclusively via EventBus.
 * - Services emit domain events (order:created, order:status-changed, etc.)
 * - This service subscribes to those events and creates notification payloads
 * - Payloads are dispatched to the appropriate NotificationAdapter by channel
 *
 * To add a new notification trigger:
 * 1. Define the event type in src/events/event-types.ts
 * 2. Add a handler method in this service
 * 3. Subscribe to the event in registerEventHandlers()
 *
 * To add a new delivery channel:
 * 1. Implement NotificationAdapter for the channel
 * 2. Register it via registerAdapter()
 *
 * Constraints:
 * - All notifications go through EventBus — no direct service calls
 * - All delivery goes through NotificationAdapter implementations
 * - Adapters must be registered before events are emitted
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationPriority,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private notifications: Notification[] = [];

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel — later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to domain events that trigger notifications.
   * All event subscriptions are centralized here.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) =>
      this.handleOrderCreated(event),
    );

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) =>
      this.handleOrderStatusChanged(event),
    );

    this.eventBus.on<UserCreatedEvent>('user:created', (event) =>
      this.handleUserCreated(event),
    );
  }

  /**
   * Handle order created — send confirmation email to user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.dispatchNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'normal',
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.dispatchNotification({
      type: 'order-status-update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority: event.newStatus === 'cancelled' ? 'high' : 'normal',
    });
  }

  /**
   * Handle user created — send welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.dispatchNotification({
      type: 'welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro',
      body: `Welcome, ${event.user.name}! Your account has been created.`,
      priority: 'normal',
    });
  }

  /**
   * Create a notification payload and dispatch it through the appropriate adapter.
   */
  async dispatchNotification(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    priority: NotificationPriority;
    metadata?: Record<string, unknown>;
  }): Promise<Notification> {
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      priority: params.priority,
      createdAt: new Date(),
      metadata: params.metadata,
    };

    const adapter = this.adapters.get(params.channel);
    if (!adapter) {
      this.logger.warn(`No adapter registered for channel: ${params.channel}`);
      const notification: Notification = {
        payload,
        results: [],
        status: 'failed',
      };
      this.notifications.push(notification);
      return notification;
    }

    const result = await adapter.send(payload);
    const notification: Notification = {
      payload,
      results: [result],
      status: result.success ? 'sent' : 'failed',
    };

    this.notifications.push(notification);
    this.logger.info(
      `Notification ${payload.id} (${params.type}) via ${params.channel}: ${notification.status}`,
    );

    return notification;
  }

  /**
   * Get all notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.payload.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Get registered adapter channels.
   */
  getRegisteredChannels(): NotificationChannel[] {
    return [...this.adapters.keys()];
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

